sql:
SELECT SUM(grant_amount) AS total_grant_amount
FROM project_grants
WHERE project_id = 1;

SELECT grant_agency, MAX(grant_amount) AS max_grant_amount
FROM project_grants
GROUP BY grant_agency;

SELECT project_id, COUNT(publication_id) AS publication_count
FROM project_publications
GROUP BY project_id;

SELECT COUNT(*) AS total_publications
FROM project_publications
WHERE project_id = 0;
